import { useState } from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

// Map condition strings to weather emoji icons
const getWeatherEmoji = (condition: string): string => {
  const lowerCondition = condition.toLowerCase();
  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloudy') || lowerCondition.includes('cloud')) return '☁️';
  if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
  if (lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('storm') || lowerCondition.includes('thunder')) return '⛈️';
  if (lowerCondition.includes('wind')) return '💨';
  if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return '🌫️';
  if (lowerCondition.includes('partly')) return '⛅';
  return '🌤️';
};

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit,
  forecast,
}: Props) {
  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with City */}
        <div>
          <Text
            variant="h2"
            color="var(--ggui-color-primary-900, #0c4a6e)"
            weight="bold"
          >
            {city}
          </Text>
        </div>

        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16}>
          {/* Temperature and Condition */}
          <Row gap={16} align="center">
            <div style={{ fontSize: '64px', lineHeight: '1' }}>
              {getWeatherEmoji(condition)}
            </div>
            <Stack direction="vertical" gap={4}>
              <div
                style={{
                  fontSize: 'var(--ggui-font-size-4xl, 36px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-primary-900, #0c4a6e)',
                  lineHeight: '1',
                }}
              >
                {temperature}°{unit}
              </div>
              <Text
                variant="body"
                color="var(--ggui-color-primary-700, #0369a1)"
                weight="semibold"
              >
                {condition}
              </Text>
            </Stack>
          </Row>

          {/* Weather Details Grid */}
          <Row gap={16} justify="between">
            {/* Humidity */}
            <Box
              padding={12}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              background="var(--ggui-color-surface, #fafafa)"
              style={{
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                flex: 1,
                textAlign: 'center',
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <div
                style={{
                  fontSize: 'var(--ggui-font-size-xl, 20px)',
                  fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                  marginTop: 'var(--ggui-spacing-1, 4px)',
                }}
              >
                {humidity}%
              </div>
            </Box>

            {/* Wind Speed */}
            <Box
              padding={12}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              background="var(--ggui-color-surface, #fafafa)"
              style={{
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                flex: 1,
                textAlign: 'center',
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind Speed
              </Text>
              <div
                style={{
                  fontSize: 'var(--ggui-font-size-xl, 20px)',
                  fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                  marginTop: 'var(--ggui-spacing-1, 4px)',
                }}
              >
                {windSpeed} km/h
              </div>
            </Box>
          </Row>
        </Stack>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            weight="semibold"
            color="var(--ggui-color-primary-900, #0c4a6e)"
          >
            5-Day Forecast
          </Text>

          <Row gap={8} justify="between" wrap>
            {forecast.map((day, index) => (
              <Box
                key={index}
                padding={12}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                background="var(--ggui-color-surface, #fafafa)"
                style={{
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  flex: '1 1 calc(20% - var(--ggui-spacing-2, 8px))',
                  minWidth: '80px',
                  textAlign: 'center',
                }}
              >
                {/* Day Name */}
                <Text
                  variant="caption"
                  weight="semibold"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {day.day}
                </Text>

                {/* Weather Icon */}
                <div style={{ fontSize: '32px', lineHeight: '1', margin: 'var(--ggui-spacing-2, 8px) 0' }}>
                  {day.icon}
                </div>

                {/* High/Low Temps */}
                <Stack direction="vertical" gap={2}>
                  <div
                    style={{
                      fontSize: 'var(--ggui-font-size-sm, 14px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      color: 'var(--ggui-color-primary-600, #0284c7)',
                    }}
                  >
                    {day.high}°
                  </div>
                  <div
                    style={{
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    }}
                  >
                    {day.low}°
                  </div>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
